swap_noninterfering_assignments.solution:
Theorem swap_noninterfering_assignments: forall l1 l2 a1 a2,
  l1 <> l2 ->
  var_not_used_in_aexp l1 a2 ->
  var_not_used_in_aexp l2 a1 ->
  cequiv <{ l1 := a1; l2 := a2 }> <{ l2 := a2; l1 := a1 }>.
Proof.
  intros l1 l2 a1 a2 Hneq H1 H2 st st'. split; intros H;
  inversion H; subst; inversion H3; subst; inversion H6; subst;
  apply E_Seq with _; apply E_Asgn; simpl;
  try (rewrite aeval_weakening; auto);
  try (rewrite t_update_permute; auto).
Qed.
